1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Damage {
14	  itemType: string;
15	  amount: number;
16	}
17	
18	interface ClaimStep {
19	  op: "claim";
20	  policy: number;
21	  incident: { cause: string; damages: Damage[] };
22	}
23	
24	type Step = QuoteStep | ClaimStep;
25	
26	interface Scenario {
27	  customer: { yearsWithMHPCO: number };
28	  steps: Step[];
29	}
30	
31	const BASE_PREMIUM: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: 25,
37	  moonstone: 25,
38	};
39	
40	const INSURANCE_VALUE: Record<string, number> = {
41	  sword: 1000,
42	  amulet: 600,
43	  staff: 800,
44	  potion: 400,
45	  rune: 250,
46	  moonstone: 250,
47	};
48	
49	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
50	const BLOCK_SIZE = 3;
51	const BLOCK_PREMIUM = 60;
52	const DEDUCTIBLE = 100;
53	const CAP_MULTIPLIER = 2;
54	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
55	const HIGH_ENCHANTMENT_REIMBURSEMENT = 0.5;
56	
57	const FIRST_INSURANCE_SURCHARGE = 0.1;
58	const CURSE_SURCHARGE = 0.5;
59	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
60	const HIGH_ENCHANTMENT_THRESHOLD = 5;
61	const LOYALTY_DISCOUNT = 0.2;
62	const LOYALTY_THRESHOLD_YEARS = 2;
63	const FOLLOWUP_DISCOUNT = 0.15;
64	const PROCESSING_FEE = 5;
65	
66	// Premiums are rounded up. We strip floating-point noise (e.g. 197.49999999)
67	// before rounding so that arithmetic artefacts don't push the result up a whole Gold.
68	const roundPremiumUp = (amount: number): number => Math.ceil(Number(amount.toFixed(6)));
69	
70	// A block applies only to a group of exactly BLOCK_SIZE alike components,
71	// priced at BLOCK_PREMIUM; any other count is priced individually.
72	const componentBasePremium = (count: number, perComponent: number): number => {
73	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
74	  return count * perComponent;
75	};
76	
77	const sum = (amounts: number[]): number => amounts.reduce((acc, amount) => acc + amount, 0);
78	
79	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
80	const isMainItem = (item: Item): boolean => !isComponent(item);
81	
82	const countByType = (items: Item[]): Record<string, number> => {
83	  const counts: Record<string, number> = {};
84	  for (const item of items) {
85	    counts[item.type] = (counts[item.type] ?? 0) + 1;
86	  }
87	  return counts;
88	};
89	
90	// A surcharge rate is an additive percentage applied on top of a base premium.
91	const applySurcharge = (base: number, rate: number): number => base * (1 + rate);
92	
93	// A conditional rate: the given percentage when its condition holds, else 0.
94	// Used for both item surcharges and policy-wide discounts.
95	const rateWhen = (applies: boolean, rate: number): number => (applies ? rate : 0);
96	
97	// Item-specific surcharges are additive percentages of the item's base premium.
98	// First insurance applies to every item; the others only when their condition holds.
99	const itemSurchargeRate = (item: Item): number =>
100	  sum([
101	    FIRST_INSURANCE_SURCHARGE,
102	    rateWhen(item.cursed === true, CURSE_SURCHARGE),
103	    rateWhen((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, HIGH_ENCHANTMENT_SURCHARGE),
104	  ]);
105	
106	const mainItemPremium = (item: Item): number =>
107	  applySurcharge(BASE_PREMIUM[item.type], itemSurchargeRate(item));
108	
109	const componentGroupBases = (items: Item[]): number[] =>
110	  Object.entries(countByType(items.filter(isComponent))).map(([type, count]) =>
111	    componentBasePremium(count, BASE_PREMIUM[type]),
112	  );
113	
114	// Sum of item base premiums with block pricing but no surcharges; the basis
115	// for policy-wide modifiers (loyalty, follow-up).
116	const policyBasePremium = (items: Item[]): number =>
117	  sum(items.filter(isMainItem).map((item) => BASE_PREMIUM[item.type])) +
118	  sum(componentGroupBases(items));
119	
120	// Sum of item premiums including item-specific surcharges (curse, high
121	// enchantment, first insurance).
122	const itemsPremium = (items: Item[]): number => {
123	  const mainItemsPremium = sum(items.filter(isMainItem).map(mainItemPremium));
124	  const componentsPremium = sum(
125	    componentGroupBases(items).map((base) => applySurcharge(base, FIRST_INSURANCE_SURCHARGE)),
126	  );
127	  return mainItemsPremium + componentsPremium;
128	};
129	
130	// Policy-wide discounts are a rate applied to the unmodified policy base.
131	// Loyalty is one such discount; the follow-up-contract discount will be another.
132	const policyWideDiscount = (rate: number, policyBase: number): number => rate * policyBase;
133	
134	const loyaltyDiscountRate = (yearsWithMHPCO: number): number =>
135	  rateWhen(yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS, LOYALTY_DISCOUNT);
136	
137	const quotePremium = (items: Item[], yearsWithMHPCO: number, isFollowup: boolean): number => {
138	  const surcharged = itemsPremium(items);
139	  const policyBase = policyBasePremium(items);
140	  const discountRate = loyaltyDiscountRate(yearsWithMHPCO) + rateWhen(isFollowup, FOLLOWUP_DISCOUNT);
141	  const discount = policyWideDiscount(discountRate, policyBase);
142	  return roundPremiumUp(surcharged - discount + PROCESSING_FEE);
143	};
144	
145	const insuranceSum = (items: Item[]): number =>
146	  sum(items.map((item) => INSURANCE_VALUE[item.type]));
147	
148	const findInsuredItem = (policyItems: Item[], itemType: string): Item | undefined =>
149	  policyItems.find((item) => item.type === itemType);
150	
151	// The damaged item's traits decide how much of the damage is reimbursed before
152	// the deductible: highly enchanted items (>= 8) are reimbursed at 50 %.
153	const reimbursement = (item: Item | undefined, amount: number): number =>
154	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
155	    ? amount * HIGH_ENCHANTMENT_REIMBURSEMENT
156	    : amount;
157	
158	const damagePayout = (damage: Damage, item: Item | undefined): number =>
159	  Math.max(0, reimbursement(item, damage.amount) - DEDUCTIBLE);
160	
161	const claimResult = (
162	  policyItems: Item[],
163	  incident: ClaimStep["incident"],
164	): { payout: number; remainingCap: number } => {
165	  const cap = CAP_MULTIPLIER * insuranceSum(policyItems);
166	  const payout = sum(
167	    incident.damages.map((damage) =>
168	      damagePayout(damage, findInsuredItem(policyItems, damage.itemType)),
169	    ),
170	  );
171	  return { payout, remainingCap: cap - payout };
172	};
173	
174	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
175	  const { yearsWithMHPCO } = scenario.customer;
176	  const policies: Record<number, Item[]> = {};
177	  let quoteCount = 0;
178	
179	  const handleQuote = (step: QuoteStep, index: number): { premium: number } => {
180	    policies[index] = step.items;
181	    const isFollowup = quoteCount > 0;
182	    quoteCount += 1;
183	    return { premium: quotePremium(step.items, yearsWithMHPCO, isFollowup) };
184	  };
185	
186	  const handleClaim = (step: ClaimStep): { payout: number; remainingCap: number } =>
187	    claimResult(policies[step.policy], step.incident);
188	
189	  const results = scenario.steps.map((step, index) =>
190	    step.op === "claim" ? handleClaim(step) : handleQuote(step, index),
191	  );
192	
193	  return { results };
194	};
